
-- ==============================================================================
-- Data Product: Carbon Emissions Data
-- Description: Stores absolute carbon emission figures (Scope 1, 2, and 3) 
--              for entities, supporting PCAF, CSRD, and net-zero target tracking.
-- ==============================================================================

-- Create Dataset
CREATE SCHEMA IF NOT EXISTS `carbon_emissions_data_v1`
  OPTIONS(
    location="europe-west1",
    description="Dataset containing greenhouse gas (GHG) emission data for entities."
  );

-- Create Table
CREATE TABLE IF NOT EXISTS `carbon_emissions_data_v1.entity_emissions` (
    emission_record_id STRING NOT NULL OPTIONS(description="Unique identifier for the emission record."),
    entity_id STRING NOT NULL OPTIONS(description="Unique identifier of the entity. Foreign key reference to entity master data."),
    reporting_year INT64 NOT NULL OPTIONS(description="The financial/calendar year the emissions relate to."),
    scope_1_emissions FLOAT64 OPTIONS(description="Direct GHG emissions in tCO2e (tonnes of CO2 equivalent)."),
    scope_2_emissions_location FLOAT64 OPTIONS(description="Indirect GHG emissions from purchased energy (location-based) in tCO2e."),
    scope_2_emissions_market FLOAT64 OPTIONS(description="Indirect GHG emissions from purchased energy (market-based) in tCO2e."),
    scope_3_emissions_total FLOAT64 OPTIONS(description="Total indirect GHG emissions in the value chain in tCO2e."),
    total_emissions FLOAT64 OPTIONS(description="Total Scope 1 + Scope 2 + Scope 3 emissions in tCO2e."),
    revenue_usd FLOAT64 OPTIONS(description="Entity revenue in USD for calculating carbon intensity."),
    carbon_intensity FLOAT64 OPTIONS(description="Emissions per unit of revenue (tCO2e / mUSD)."),
    data_quality_score INT64 OPTIONS(description="PCAF data quality score (1-5, where 1 is highest quality)."),
    PRIMARY KEY (emission_record_id) NOT ENFORCED
)
OPTIONS(
  description="Table storing annual Scope 1, 2, and 3 GHG emissions data."
);

